//! Auto-generated by the spec-word-compliance workflow for area
//! "Paragraph pagination and line-keeping control".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 for the paragraph pagination and line-keeping
//! control properties (autoSpaceDE/DN, snapToGrid, adjustRightInd,
//! pageBreakBefore vs keepNext, kinsoku/overflowPunct, widowControl,
//! suppressAutoHyphens, suppressOverlap, topLinePunct, mirrorIndents,
//! wordWrap).
//!
//! A FAILING assertion in this file is NOT something to "make pass" by
//! weakening the test: it encodes a real Word-compliance gap in stemma — the
//! engine diverges from what Microsoft Word does when consuming this markup.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim. So these tests deliberately assert layout/consumption
//! semantics on the READ side (accept/reject text) and structural VALIDITY via
//! the validator (opens-clean) — NOT `xmlOmits` of verbatim-preserved
//! attributes, which would be a test bug for these render-only flags.

use std::io::Read;

use stemma::api::Document;

// ─── Prelude / helpers ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx` from a `<w:body>` fragment. `extra_parts` is a
/// list of `(part_path, xml)` (e.g. `("word/styles.xml", "<w:styles…/>")`); a
/// matching `[Content_Types].xml` override + document rel is emitted for each.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override per known extra part.
    let mut overrides = String::new();
    for (part, _) in extra_parts {
        let ct = match *part {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content-type known for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // Document rels: relate any extra parts (styles/numbering) so the
    // references resolve the way Word expects.
    let mut doc_rels_body = String::new();
    for (rid, (part, _)) in (1..).zip(extra_parts.iter()) {
        let (rel_type, target) = match *part {
            "word/styles.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            other => panic!("make_docx: no rel type known for extra part {other}"),
        };
        doc_rels_body.push_str(&format!(
            r#"<Relationship Id="rIdX{rid}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rels_body}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip archive");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in archive");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Parse -> serialize (ExportOptions::default) -> document.xml of the result.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert the package opens clean in the stemma validator (no issues).
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected the package to open clean (no validator issues), got: {:?}",
        report.issues
    );
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for read_accepted")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse for read_rejected")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

// ─── Tests ──────────────────────────────────────────────────────────────────

#[test]
fn autospacede_val_off_is_off_and_opens_clean() {
    let body = r#"<w:p><w:pPr><w:autoSpaceDE w:val="0"/></w:pPr><w:r><w:t>East Asian spacing off</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "autoSpaceDE val=0 [ISO 29500-1 §17.3.1.2, §17.17.4]: \
         CT_OnOff toggle at CT_PPrBase pos 16; val=0 is an in-domain ST_OnOff literal, Word opens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "East Asian spacing off",
        "autoSpaceDE val=0 [ISO 29500-1 §17.3.1.2]: \
         autoSpaceDE only governs inter-character spacing between Latin and East-Asian regions; \
         turning it off adds/removes no characters, so accepted reading equals the verbatim run text",
    );
}

