#[test]
fn page_break_before_supersedes_keep_next_layout_only() {
    let body = r#"<w:p><w:pPr><w:keepNext/><w:pageBreakBefore/></w:pPr><w:r><w:t>Kept and page-broken paragraph</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "pageBreakBefore + keepNext [ECMA-376 §17.17.4]: \
         bare keepNext and pageBreakBefore are valid present-implied-true CT_OnOff toggles, Word opens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Kept and page-broken paragraph",
        "pageBreakBefore + keepNext [ECMA-376 §17.3.1.23]: \
         pageBreakBefore superseding keepNext is layout-only; neither is a content property, \
         so accepted reading is the verbatim run text",
    );
    assert_eq!(
        reject_text(&b),
        "Kept and page-broken paragraph",
        "pageBreakBefore + keepNext [ECMA-376 §17.3.1.23/§17.3.1.15]: \
         both keep/break toggles are page-placement only; rejecting adds/removes no characters, \
         so rejected reading is the verbatim run text",
    );
}

#[test]
fn overflow_punct_overrides_kinsoku_on_conflict_text_verbatim() {
    let body = r#"<w:p><w:pPr><w:kinsoku/><w:overflowPunct w:val="0"/></w:pPr><w:r><w:t>Punctuation overhang versus kinsoku.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "kinsoku + overflowPunct [ISO 29500-1 §17.17.4]: \
         bare kinsoku (present-implied-true) and overflowPunct val=0 (off literal) are valid CT_OnOff toggles, \
         Word opens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Punctuation overhang versus kinsoku.",
        "kinsoku + overflowPunct [MS-OI29500 §2.1.52]: \
         Word's overflowPunct-over-kinsoku tie-break is a line-breaking layout decision; \
         it adds/removes no characters, so accepted reading is the verbatim run text",
    );
}

#[test]
fn widow_control_bare_present_means_on_layout_only_text_verbatim() {
    let body = r#"<w:p><w:pPr><w:widowControl/></w:pPr><w:r><w:t>Widow control on by bare element.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "widowControl bare [ECMA-376 §17.17.4]: \
         a bare CT_OnOff element is valid (val omitted = true); Word opens widowControl without repair",
    );
    assert_eq!(
        accept_text(&b),
        "Widow control on by bare element.",
        "widowControl bare [ISO 29500-1 §17.3.1.44]: \
         widowControl only moves lines between pages at display time; it changes no run characters, \
         so accepted reading is the verbatim run text",
    );
    assert_eq!(
        reject_text(&b),
        "Widow control on by bare element.",
        "widowControl bare [ISO 29500-1 §17.3.1.44]: \
         widow/orphan control is page-placement only; rejecting adds/removes no characters, \
         so rejected reading is the verbatim run text",
    );
}

#[test]
fn suppress_auto_hyphens_bare_present_layout_only_opens_clean() {
    let body = r#"<w:p><w:pPr><w:suppressAutoHyphens/></w:pPr><w:r><w:t>This paragraph is exempt from hyphenation.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "suppressAutoHyphens bare [ECMA-376 §17.17.4]: \
         a bare CT_OnOff element is valid (val omitted = true); Word opens suppressAutoHyphens without repair",
    );
    assert_eq!(
        accept_text(&b),
        "This paragraph is exempt from hyphenation.",
        "suppressAutoHyphens bare [ISO 29500-1 §17.3.1.34]: \
         hyphenation is applied/suppressed only at display time; soft hyphens are not stored text, \
         so accepted reading is the verbatim run text",
    );
    assert_eq!(
        reject_text(&b),
        "This paragraph is exempt from hyphenation.",
        "suppressAutoHyphens bare [ISO 29500-1 §17.3.1.34]: \
         display-time only; rejecting adds/removes no characters, so rejected reading is the verbatim run text",
    );
}

#[test]
fn suppress_overlap_present_implied_true_layout_only() {
    let body = r#"<w:p><w:pPr><w:framePr w:w="2191" w:h="811" w:hRule="exact" w:wrap="around" w:vAnchor="text" w:hAnchor="page" w:x="1921"/><w:suppressOverlap/></w:pPr><w:r><w:t>Frame text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "suppressOverlap bare [ECMA-376 §17.17.4 + wml.xsd]: \
         a bare CT_OnOff suppressOverlap child of pPr is schema-valid, Word opens without a repair prompt",
    );
    assert_eq!(
        accept_text(&b),
        "Frame text",
        "suppressOverlap bare [ECMA-376 §17.3.1.36]: \
         suppressOverlap is display-time frame repositioning only and adds no characters, \
         so accepted reading is the verbatim run text",
    );
    assert_eq!(
        reject_text(&b),
        "Frame text",
        "suppressOverlap bare [ECMA-376 §17.3.1.36]: \
         a layout-only toggle changes no run content, so rejected reading is identical verbatim text",
    );
}

